### 2. **Добавить WebSocket функционал:**

```javascript
// composables/useWebSocket.js
import { ref, onMounted, onUnmounted } from 'vue'

export function useWebSocket() {
  const ws = ref(null)
  const connected = ref(false)
  const messages = ref([])

  const connect = (token) => {
    ws.value = new WebSocket('ws://localhost:8080')

    ws.value.onopen = () => {
      connected.value = true
      ws.value.send(JSON.stringify({ type: 'auth', token }))
    }

    ws.value.onmessage = (event) => {
      const data = JSON.parse(event.data)
      messages.value.push(data)
      // handle different message types
    }

    ws.value.onclose = () => {
      connected.value = false
    }
  }

  const send = (data) => {
    if (ws.value?.readyState === WebSocket.OPEN) {
      ws.value.send(JSON.stringify(data))
    }
  }

  onUnmounted(() => {
    ws.value?.close()
  })

  return { connect, send, connected, messages }
}
```

### 3. **Минимальные страницы:**
- Training page (уже есть?)
- Challenge/Matchmaking page (новая)
- Простой UI для демо

