import { ref } from 'vue'
import axios from 'axios'

export function useTrainings() {
  const trainings = ref([])
  const loading = ref(false)
  const errors = ref([])

  async function fetchTrainings(statuses = []) {
    loading.value = true
    errors.value = []
    const params = new URLSearchParams()

    if (statuses.length) {
      params.append('filter[status]', statuses.join(','))
    }
    axios
      .get(`/trainings?${params.toString()}`)
      .then((response) => {
        loading.value = false
        if (response.data.success === true) {
          trainings.value = response.data.data
        } else {
          console.log('Error fetching trainings:', response.data.message)
        }
      })
      .catch((error) => {
        loading.value = false
        errors.value = error.response ? error.response.data.errors : [error.message]
      })
  }

  return {
    trainings,
    loading,
    errors,
    fetchTrainings,
  }
}
